var partitionString = function(s) {
    const seen = new Set();
    let count = 1;
    for (const ch of s) {
        if (seen.has(ch)) {
            count++;
            seen.clear();
            seen.add(ch);
        } else {
            seen.add(ch);
        }
    }
    return count;
